type DeepPartial<T> = { [P in keyof T]?: T[P] extends object ? DeepPartial<T[P]> : T[P] }

export interface User {
  id: string
  email: string
  name: string
  phone: string
  role: 'customer' | 'admin' | 'superadmin'
  avatar: string | null
  emailVerified: boolean
  createdAt: string
}

let _userCounter = 0

const FIRST_NAMES = ['Juan', 'Maria', 'Carlos', 'Ana', 'Pedro', 'Lucia', 'Diego', 'Sofia', 'Luis', 'Elena']
const LAST_NAMES = ['Gonzalez', 'Rodriguez', 'Lopez', 'Martinez', 'Perez', 'Garcia', 'Diaz', 'Fernandez']

function pick<T>(arr: T[]): T {
  return arr[Math.floor(Math.random() * arr.length)]
}

export function generateUser(overrides: DeepPartial<User> = {}): User {
  _userCounter++
  const name = overrides.name ?? `${pick(FIRST_NAMES)} ${pick(LAST_NAMES)}`
  return {
    id: overrides.id ?? `user_${_userCounter}`,
    email: overrides.email ?? `user${_userCounter}@example.com`,
    name,
    phone: overrides.phone ?? `+595981${_userCounter.toString().padStart(6, '0')}`,
    role: overrides.role ?? 'customer',
    avatar: overrides.avatar ?? null,
    emailVerified: overrides.emailVerified ?? true,
    createdAt: overrides.createdAt ?? new Date().toISOString(),
  }
}

export function generateAdminUser(overrides: DeepPartial<User> = {}): User {
  return generateUser({ ...overrides, role: 'admin' })
}

export function generateUserList(count: number, overrides: DeepPartial<User> = {}): User[] {
  return Array.from({ length: count }, () => generateUser(overrides))
}
